function buildParams(segment, account, dataTopic, accessToken) {
  const advertiser_id = account.advertiser_id;
  const aweme_id = account.aweme_id || "";
  const start_time = segment.start_time;
  const end_time = segment.end_time;
  const page = 1;
  const page_size = 100;

  let dimensions, filters, metrics, order_by;

  if (dataTopic === DATA_TOPIC.LIVE) {
    dimensions = JSON.stringify(LIVE_DIMS);
    filters = JSON.stringify([
      { field: "anchor_id", operator: 7, values: [aweme_id] },
      { field: "ecp_app_id", operator: 7, values: ["1", "2"] },
      { field: "aggregate_smart_bid_type", operator: 7, values: ["0"] }
    ]);
    metrics = JSON.stringify(LIVE_IND_KEYS);
    order_by = JSON.stringify([{ field: "stat_time_day", type: 1 }]);
  } else if (dataTopic === DATA_TOPIC.VIDEO) {
    dimensions = JSON.stringify(VIDEO_DIMS);
    filters = JSON.stringify([
      { field: "anchor_id", operator: 7, values: [aweme_id] },
      { field: "ecp_app_id", operator: 7, values: ["1", "2"] },
      { field: "aggregate_smart_bid_type", operator: 7, values: ["0"] }
    ]);
    metrics = JSON.stringify(VIDEO_IND_KEYS);
    order_by = JSON.stringify([{ field: "stat_time_day", type: 1 }, { field: "material_id", type: 1 }]);
  } else {
    dimensions = JSON.stringify(OTHER_DIMS);
    filters = JSON.stringify([
      { field: "anchor_id", operator: 7, values: [aweme_id] },
      { field: "ecp_app_id", operator: 7, values: ["1", "2"] },
      { field: "aggregate_smart_bid_type", operator: 7, values: ["0"] }
    ]);
    metrics = JSON.stringify(OTHER_IND_KEYS);
    order_by = JSON.stringify([{ field: "stat_time_day", type: 1 }]);
  }

  return {
    access_token: accessToken,
    advertiser_id,
    aweme_id,
    account_name: account.account_name,
    data_topic: dataTopic,
    start_time,
    end_time,
    dimensions,
    filters,
    metrics,
    order_by,
    page,
    page_size
  };
}

// ---------- n8n 入口 ----------
// Token 来源：优先「查库取Token」；需要刷新时从「Token刷新」HTTP 节点取 data.access_token，或从刷新分支上的 Set/Code（如「构造Token」）取 access_token；也可用上游 item 或环境变量（请按实际节点名修改）
// const tokenFromDb = $(巨量千川token查询')?.first()?.json?.access_token;
// const tokenFromRefreshNode = $('Token刷新')?.first()?.json?.data?.access_token;
// const tokenFromSet = $('构造Token')?.first()?.json?.access_token;
// const tokenFromInput = $input.first()?.json?.access_token;
// const accessToken = tokenFromDb || tokenFromRefreshNode || tokenFromSet || tokenFromInput || $env?.OCEAN_ENGINE_ACCESS_TOKEN;
const accessToken = $input.first().json.access_token

if (!accessToken) {
  throw new Error("缺少 access_token，请确保上游有「查库取Token」或「刷新后写回库」节点，或在本流程前提供 access_token");
}

// 时间拆分节点输出的多条 item（每条只有 start_time, end_time，可能带 mode 等）
const timeSegments = $input.all().map((i) => i.json);

const topics = [DATA_TOPIC.LIVE, DATA_TOPIC.VIDEO, DATA_TOPIC.OTHER];
const out = [];

for (const segment of timeSegments) {
  for (const account of ACCOUNTS) {
    for (const dataTopic of topics) {
      out.push({ json: buildParams(segment, account, dataTopic, accessToken) });
    }
  }
}

return out;

} catch (error) {
  console.error('节点执行错误:', error);
  return [{ json: { _error: true, message: error.message || String(error), node: '组合请求参数' } }];
}

