const items = $input.all();
const results = [];

// 🔥 核心修正：把变量提取和时间初始化移到【所有循环的最外层】🔥
const advertiserId = $('是否直播画面接口').first().json.advertiser_id;
const startTime = $('是否直播画面接口').first().json.start_time;

const safeStartTime = startTime.replace(' ', 'T'); 
let currentTimestamp = new Date(safeStartTime).getTime();

// 遍历 n8n 的每一个数据批次 (Item)
for (const item of items) {
