    // 3. 解析当前行并存入结果
    const parsed = parseRow(row, advertiserId, timeString);
    results.push({ json: orderColumns(parsed) });

    // 4. 当前行处理完毕，时间戳累加 1 分钟，继续走下一个循环
    currentTimestamp += 60000;
  }
}

return results.length ? results : [{ json: { _empty: true } }];
} catch (error) {
  console.error('节点执行错误:', error);
