// ========== n8n Code 节点：千川素材 - 时间拆分 ==========
// 输入：Run Once for All Items，取 items[0].json 的 start_time、end_time（格式 "YYYY-MM-DD HH:mm:ss"）
// 或由上游传入单条：{ start_time, end_time }；可选 mode: "minute" | "hour" | "day"
// 输出：多条 item，每条 { start_time, end_time }，供下游「按时间段 + 账户」请求 API

function parseDt(str) {
  const d = new Date(str.replace(" ", "T"));
  if (isNaN(d.getTime())) throw new Error("时间格式错误，需 YYYY-MM-DD HH:mm:ss");
  return d;
}

function formatDt(d) {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  const h = String(d.getHours()).padStart(2, "0");
  const min = String(d.getMinutes()).padStart(2, "0");
  const s = String(d.getSeconds()).padStart(2, "0");
  return `${y}-${m}-${day} ${h}:${min}:${s}`;
}

/** 按天再按分钟拆分：每段为 [整分:00, 整分:59] */
function splitTimeByDayThenMinute(totalStart, totalEnd) {
  const list = [];
  let currentDay = parseDt(totalStart);
  const endDt = parseDt(totalEnd);
  if (currentDay >= endDt) return list;

  while (currentDay < endDt) {
    const dayStart = new Date(currentDay.getFullYear(), currentDay.getMonth(), currentDay.getDate(), 0, 0, 0);
    let dayEnd = new Date(dayStart);
    dayEnd.setDate(dayEnd.getDate() + 1);
    dayEnd.setSeconds(dayEnd.getSeconds() - 1);
    if (dayEnd > endDt) dayEnd = endDt;

    let currentMinute = dayStart;
    while (currentMinute <= dayEnd) {
      const minuteStart = new Date(currentMinute);
      minuteStart.setSeconds(0);
      let minuteEnd = new Date(minuteStart);
      minuteEnd.setMinutes(minuteEnd.getMinutes() + 1);
      minuteEnd.setSeconds(minuteEnd.getSeconds() - 1);
      if (minuteEnd > endDt) minuteEnd = endDt;
      list.push({ start_time: formatDt(minuteStart), end_time: formatDt(minuteEnd) });
      currentMinute = new Date(minuteStart);
      currentMinute.setMinutes(currentMinute.getMinutes() + 1);
    }
    currentDay = new Date(dayStart);
    currentDay.setDate(currentDay.getDate() + 1);
  }
  return list;
}

/** 按小时拆分：每段 整点:00:00 ~ 整点:59:59 */
function splitTimeByHour(totalStart, totalEnd) {
  const list = [];
  const startDt = parseDt(totalStart);
  const endDt = parseDt(totalEnd);
  if (startDt >= endDt) return list;

  let current = new Date(startDt);
  current.setMinutes(0, 0, 0);
  while (current < endDt) {
    let hourEnd = new Date(current);
    hourEnd.setHours(hourEnd.getHours() + 1);
    hourEnd.setSeconds(hourEnd.getSeconds() - 1);
    if (hourEnd > endDt) hourEnd = endDt;
    if (current < hourEnd) {
      list.push({ start_time: formatDt(current), end_time: formatDt(hourEnd) ,accesstoken});
    }
    current.setHours(current.getHours() + 1);
  }
  return list;
}

/** 按自然日拆分：当天 00:00:00 ~ 23:59:59 */
function splitTimeByDay(totalStart, totalEnd) {
  const list = [];
  const startDt = parseDt(totalStart);
  const endDt = parseDt(totalEnd);
  if (startDt >= endDt) return list;

  let current = new Date(startDt);
  current.setHours(0, 0, 0, 0);
  while (current < endDt) {
    let dayEnd = new Date(current);
    dayEnd.setDate(dayEnd.getDate() + 1);
    dayEnd.setSeconds(dayEnd.getSeconds() - 1);
    if (dayEnd > endDt) dayEnd = endDt;
    if (current < dayEnd) {
      list.push({ start_time: formatDt(current), end_time: formatDt(dayEnd) });
    }
    current.setDate(current.getDate() + 1);
  }
  return list;
}

